On 21 April 1999, Dom Mitchell proclaimed:
> What do you get?  I have a feeling that it could just be a question
> of making python's configure understand FreeBSD 4.0, as there appear
> to be some hardcoded FreeBSD3's in there.

That was it.  The enclosed patch (when put into the port's patches
directory) fixes the problem for me.  I'll send this to guido as a
python bug.

--- configure.orig	Wed Apr 21 16:45:13 1999
+++ configure	Wed Apr 21 16:47:24 1999
@@ -2246,7 +2249,7 @@
 		fi ;;
 	Linux*) LDSHARED="gcc -shared";;
 	dgux*) LDSHARED="ld -G";;
-	FreeBSD*/3*) LDSHARED="gcc -shared";;
+	FreeBSD*/[34]*) LDSHARED="gcc -shared";;
 	FreeBSD*|OpenBSD*) LDSHARED="ld -Bshareable";;
 	NetBSD*)
 		if [ "`$CC -dM -E - </dev/null | grep __ELF__`" != "" ]
@@ -2292,7 +2295,7 @@
 	AIX*)	LINKFORSHARED='-Wl,-bE:python.exp -lld';;
 	hp*|HP*)
 	    LINKFORSHARED="-Wl,-E -Wl,+s -Wl,+b\$(BINLIBDEST)/lib-dynload";;
-	FreeBSD/3*) LINKFORSHARED="-Xlinker -export-dynamic";;
+	FreeBSD/[34]*) LINKFORSHARED="-Xlinker -export-dynamic";;
 	Linux*) LINKFORSHARED="-Xlinker -export-dynamic";;
 	# -u libsys_s pulls in all symbols in libsys
 	next/2*|next/3*) LINKFORSHARED="-u libsys_s";;

